import dspy

class ClassifyIntent(dspy.Signature):
    '''Classify customer support intent.'''
    query = dspy.InputField()
    intent = dspy.OutputField(desc='billing|technical|order|escalation')
    reasoning = dspy.OutputField(desc='Step-by-step reasoning')

class IntentModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.ChainOfThought(ClassifyIntent)

    def forward(self, query: str) -> dict:
        return self.classify(query=query)

class RetrieveContext(dspy.Module):
    def __init__(self, retriever):
        super().__init__()
        self.retriever = retriever
        self.generate_query = dspy.ChainOfThought('query -> search_query')

    def forward(self, query: str, crm_data: dict) -> dict:
        search_query = self.generate_query(query=query).search_query
        kb_results = self.retriever(search_query)
        context = {'kb': kb_results, 'crm': crm_data}
        return {'context': context, 'query': query}

class ToolCall(dspy.Signature):
    '''Call CRM tools for customer support.'''
    context = dspy.InputField()
    intent = dspy.InputField()
    tools_needed = dspy.OutputField(desc='order_lookup|create_ticket|none')
    tool_params = dspy.OutputField(desc='JSON parameters')

class ToolModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.tools = dspy.ChainOfThought(ToolCall)

    def forward(self, context: dict, intent: str) -> dict:
        pred = self.tools(context=context, intent=intent)
        return self._execute_tools(pred)

class GenerateResponse(dspy.Signature):
    '''Generate helpful customer support response.'''
    context = dspy.InputField()
    intent = dspy.InputField()
    tools_result = dspy.InputField()
    response = dspy.OutputField(desc='Professional, empathetic response')
    escalate = dspy.OutputField(desc='yes|no')

class ResponseModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(GenerateResponse)

    def forward(self, context: dict, intent: str, tools_result: dict) -> dict:
        return self.generate(context=context, intent=intent, tools_result=tools_result)

